mapper.sql:
where e.deleted = 0

    and e.enterprise_name like concat('%', #{query.enterpriseName}, '%')


    and e.industry = #{query.industry}


    and e.enterprise_nature = #{query.enterpriseNature}


    and e.enterprise_scale = #{query.enterpriseScale}


    and e.region_county_code = #{query.regionCountyCode}


    and e.region_city_code = #{query.regionCityCode}


    and e.region_province_code = #{query.regionProvinceCode}

mapper.select:
select e.id, e.enterprise_name, coalesce(di.dict_label, e.industry) as industry, coalesce(dn.dict_label, e.enterprise_nature) as enterprise_nature, coalesce(ds.dict_label, e.enterprise_scale) as enterprise_scale, e.region_province_code, e.region_city_code, e.region_county_code, concat_ws('-', rp.region_name, rc.region_name, rct.region_name) as region_name, e.unified_social_credit_code, e.business_license_path, e.address, e.contact_person, e.contact_phone, e.description, e.status from enterprise_info e left join sys_dict_item di on di.dict_type = 'enterprise_industry' and di.dict_value = e.industry and di.enabled = 1 left join sys_dict_item dn on dn.dict_type = 'enterprise_nature' and dn.dict_value = e.enterprise_nature and dn.enabled = 1 left join sys_dict_item ds on ds.dict_type = 'enterprise_scale' and ds.dict_value = e.enterprise_scale and ds.enabled = 1 left join sys_region rp on rp.region_code = e.region_province_code left join sys_region rc on rc.region_code = e.region_city_code left join sys_region rct on rct.region_code = e.region_county_code
order by e.id desc
limit #{query.offset}, #{query.safePageSize}

mapper.update:
update enterprise_info
set deleted = 1,
    update_by = #{updateBy}
where id = #{id}
  and deleted = 0

update enterprise_info
set deleted = 1,
    update_by = #{updateBy}
where deleted = 0
  and id in

    #{id}
